window.partFormatter=function(n){var t;return t+="<button class='btn btn-sm btn-info m-1 usePart' data-id='"+n+"'>استفاده<\/button>",t+("<button class='btn btn-sm btn-info m-1 addDescription' data-id='"+n+"'>افزودن به توضیحات<\/button>")};window.partsAdditionalParams=function(){return{Brand:$(".part-list #Brand").val(),Model:$(".part-list #Model").val()}};window.phonesAdditionalParams=function(){return{Brand:$(".phone-list #Brand").val(),Model:$(".phone-list #Model").val()}};